    }
}

import React, { useState, useEffect } from 'react';
import { Lightbulb, Loader2, X, TrendingUp, TrendingDown, ExternalLink, RefreshCw, Search, CheckSquare, Square, Plus, Check } from 'lucide-react';
import { fetchSectorInsights } from '../../services/dataService';
import { SectorInsightItem } from '../../types/trackingTypes';
import { getTrackedItems, addTrackedItem, removeTrackedItem } from '../../services/trackingStorage';

interface SectorInsightsWidgetProps {
  sectorName: string;
  sectorUrl: string;
  onAddToMover: (symbol: string) => void;
  onNavigateStock?: (symbol: string, name: string) => void;
  addedSymbols?: string[];
}

const SectorInsightsWidget: React.FC<SectorInsightsWidgetProps> = ({ 
    sectorName, 
    sectorUrl,
    onAddToMover,
    onNavigateStock,
    addedSymbols = []
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [data, setData] = useState<SectorInsightItem[]>([]);
  const [hasFetched, setHasFetched] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [trackedSet, setTrackedSet] = useState<Set<string>>(new Set());

  // Load tracked items and listen for updates
  useEffect(() => {
      const updateTracked = () => {
          const items = getTrackedItems().filter(i => i.type === 'STOCK');
          setTrackedSet(new Set(items.map(i => i.id)));
      };
      updateTracked();
      window.addEventListener('fundflow_tracking_update', updateTracked);
      return () => window.removeEventListener('fundflow_tracking_update', updateTracked);
  }, []);

  // Lock body scroll when modal is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => document.body.style.overflow = 'unset';
  }, [isOpen]);

  const loadData = async () => {
      setIsLoading(true);
      try {
          // Ensure URL is absolute for fetching
          const fetchUrl = sectorUrl.startsWith('http') ? sectorUrl : `https://trendlyne.com${sectorUrl}`;
          const insights = await fetchSectorInsights(fetchUrl);
          setData(insights);
          setHasFetched(true);
      } catch (error) {
          console.error("Failed to fetch sector insights", error);
      } finally {
          setIsLoading(false);
      }
  };

  const handleToggle = async (e: React.MouseEvent) => {
      e.stopPropagation();
      setIsOpen(true);
      if (!hasFetched) {
          await loadData();
      }
  };

  const handleRefresh = async () => {
      await loadData();
  };

  const handleTrackToggle = (e: React.MouseEvent, symbol: string, name: string) => {
      e.stopPropagation();
      if (trackedSet.has(symbol)) {
          removeTrackedItem(symbol, 'STOCK');
      } else {
          addTrackedItem({ id: symbol, name, symbol, type: 'STOCK' });
      }
  };

  const handleAddToMoverClick = (e: React.MouseEvent, symbol: string) => {
      e.stopPropagation();
      onAddToMover(symbol);
  };

  const handleNavigate = (e: React.MouseEvent, symbol: string, name: string) => {
      e.stopPropagation();
      if (onNavigateStock) {
          onNavigateStock(symbol, name);
          setIsOpen(false);
      }
  };

  // Filter Logic
  const filteredData = data.filter(item => {
      if (searchQuery.trim()) {
          return item.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                 item.tooltip_stock_name.toLowerCase().includes(searchQuery.toLowerCase());
      }
      return true; // Show all by default
  });

  // Count tracked stocks in this sector
  const trackedCount = data.filter(item => trackedSet.has(item.name)).length;

  return (
    <>
        <button 
            onClick={handleToggle}
            className={`p-1.5 rounded-full transition-all shadow-sm flex items-center gap-1 ${
                hasFetched 
                ? 'bg-indigo-100 text-indigo-700 hover:bg-indigo-200' 
                : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
            }`}
            title={`View Stocks in ${sectorName}`}
        >
            <Lightbulb size={12} className={hasFetched ? "fill-indigo-700" : ""} />
            {hasFetched && trackedCount > 0 && (
                <span className="text-[9px] font-bold">{trackedCount}</span>
            )}
        </button>

        {isOpen && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in" onClick={() => setIsOpen(false)}>
                <div 
                    className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden animate-scale-in border border-gray-200"
                    onClick={(e) => e.stopPropagation()}
                >
                    {/* Header */}
                    <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between gap-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                                <Lightbulb size={20} />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-gray-900 leading-tight">{sectorName}</h2>
                                <p className="text-xs text-gray-500">Sector Analysis & Constituents</p>
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                             <button 
                                onClick={handleRefresh}
                                disabled={isLoading}
                                className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-white rounded-lg transition-colors border border-transparent hover:border-gray-200"
                                title="Refresh Data"
                            >
                                <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                            </button>
                            <button 
                                onClick={() => setIsOpen(false)}
                                className="p-2 text-gray-500 hover:text-gray-700 hover:bg-red-50 rounded-lg transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>
                    </div>

                    {/* Search Bar */}
                    <div className="p-4 border-b border-gray-100 bg-white sticky top-0 z-10">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                            <input 
                                type="text"
                                placeholder={`Search stocks in ${sectorName}...`}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                autoFocus
                            />
                        </div>
                    </div>

                    {/* Content */}
                    <div className="overflow-y-auto p-4 custom-scrollbar bg-gray-50/50 flex-1">
                        {isLoading ? (
                            <div className="flex flex-col items-center justify-center py-12 text-gray-400 gap-3">
                                <Loader2 size={32} className="animate-spin text-indigo-500" />
                                <span className="text-sm font-medium">Fetching Sector Constituents...</span>
                            </div>
                        ) : filteredData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-12 text-gray-400 gap-2 text-center">
                                <Search size={32} className="opacity-20" />
                                <p className="text-sm">No stocks found matching "{searchQuery}"</p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                {filteredData.map((item) => {
                                    const isTracked = trackedSet.has(item.name);
                                    const isAdded = addedSymbols.includes(item.name);
                                    const isPositive = item.value >= 0;

                                    return (
                                        <div 
                                            key={item.id}
                                            className={`group p-3 rounded-xl border transition-all flex gap-3 items-start ${
                                                isTracked 
                                                ? 'bg-indigo-50/40 border-indigo-200 shadow-sm' 
                                                : 'bg-white border-gray-200 hover:border-indigo-200 hover:shadow-sm'
                                            }`}
                                        >
                                            {/* Checkbox for Tracking */}
                                            <button 
                                                onClick={(e) => handleTrackToggle(e, item.name, item.tooltip_stock_name)}
                                                className={`mt-0.5 shrink-0 transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 hover:text-gray-500'}`}
                                                title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
                                            >
                                                {isTracked ? <CheckSquare size={18} /> : <Square size={18} />}
                                            </button>

                                            {/* Content */}
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center justify-between mb-1">
                                                    <button 
                                                        onClick={(e) => handleNavigate(e, item.name, item.tooltip_stock_name)}
                                                        className="font-bold text-sm text-gray-900 hover:text-indigo-600 hover:underline flex items-center gap-1.5 transition-colors truncate"
                                                        title={item.tooltip_stock_name}
                                                    >
                                                        {item.name}
                                                    </button>

                                                    {/* Change % */}
                                                    <span className={`text-xs font-bold ${isPositive ? 'text-green-600' : 'text-red-600'}`}>
                                                        {item.disp_value}
                                                    </span>
                                                </div>

                                                <div className="flex items-center justify-between mt-2">
                                                    <div className="flex items-center gap-2">
                                                        <a 
                                                            href={item.cell_url}
                                                            target="_blank"
                                                            rel="noreferrer"
                                                            className="text-gray-400 hover:text-indigo-600 transition-colors"
                                                            title="View on Trendlyne"
                                                            onClick={(e) => e.stopPropagation()}
                                                        >
                                                            <ExternalLink size={12} />
                                                        </a>
                                                    </div>

                                                    {isAdded ? (
                                                        <span className="text-green-600 text-[10px] font-medium flex items-center gap-1 bg-green-50 px-2 py-0.5 rounded border border-green-100">
                                                            <Check size={10} /> Added
                                                        </span>
                                                    ) : (
                                                        <button 
                                                            onClick={(e) => handleAddToMoverClick(e, item.name)}
                                                            className="text-indigo-600 bg-indigo-50 hover:bg-indigo-100 px-2 py-1 rounded text-[10px] flex items-center gap-1 border border-indigo-100 transition-colors"
                                                            title="Add to Portfolio Updates"
                                                        >
                                                            <Plus size={12} /> Add
                                                        </button>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>

                    {/* Footer */}
                    <div className="p-3 bg-gray-50 border-t border-gray-200 text-center text-xs text-gray-400">
                        {data.length} stocks in {sectorName}
                    </div>
                </div>
            </div>
        )}
    </>
  );
};

export default SectorInsightsWidget;

import React, { useState, useMemo, useEffect } from 'react';
import { Calendar, Search, Loader2, RefreshCw, ExternalLink, ArrowUp, ArrowDown, Minus, ChevronDown, CheckSquare, Square } from 'lucide-react';
import { SectorPulseItem, SectoralData } from '../../types/trackingTypes';
import { getTrackedIndices, addTrackedIndex, removeTrackedIndex } from '../../services/trackingStorage';
import SectorInsightsWidget from './SectorInsightsWidget';

interface SectoralPulseProps {
  data: SectoralData | null;
  loading: boolean;
  onRefresh: () => void;
  duration: string;
  onDurationChange: (duration: string) => void;
  onAddMover: (symbol: string) => void;
  onSelectStock?: (symbol: string, name: string) => void;
  addedSymbols?: string[];
}

const SectoralPulse: React.FC<SectoralPulseProps> = ({ 
    data, 
    loading, 
    onRefresh, 
    duration, 
    onDurationChange,
    onAddMover,
    onSelectStock,
    addedSymbols = []
}) => {
  const [activeTab, setActiveTab] = useState<'SECTOR' | 'INDUSTRY' | 'INDEX'>('SECTOR');
  const [searchQuery, setSearchQuery] = useState('');
  const [trackedIndices, setTrackedIndices] = useState<string[]>([]);

  useEffect(() => {
      const updateTracked = () => setTrackedIndices(getTrackedIndices());
      updateTracked();
      window.addEventListener('fundflow_tracking_update', updateTracked);
      return () => window.removeEventListener('fundflow_tracking_update', updateTracked);
  }, []);

  const handleToggleTrack = (name: string) => {
      if (trackedIndices.includes(name)) {
          removeTrackedIndex(name);
      } else {
          addTrackedIndex(name);
      }
  };

  const DURATION_OPTIONS = [
      { label: 'Day', value: '1D' },
      { label: 'Week', value: '1W' },
      { label: 'Month', value: '1M' },
      { label: 'Quarter', value: '3M' },
      { label: 'Year', value: '1Y' },
  ];

  const getActiveList = () => {
      if (!data) return [];
      switch (activeTab) {
          case 'SECTOR': return data.sectors;
          case 'INDUSTRY': return data.industries;
          case 'INDEX': return data.indices.filter(i => i.name.toUpperCase().includes('NIFTY'));
          default: return [];
      }
  };

  const processList = (list: SectorPulseItem[]) => {
      // 1. Sort by Change Percent Descending
      const sorted = [...list].sort((a, b) => b.changePercent - a.changePercent);

      // 2. Filter or Slice
      if (searchQuery.trim()) {
          const q = searchQuery.toLowerCase();
          return sorted.filter(item => item.name.toLowerCase().includes(q));
      } else {
          // Top 5 and Bottom 5
          if (sorted.length <= 10) return sorted;
          const top5 = sorted.slice(0, 5);
          const bottom5 = sorted.slice(-5);
          // Ensure no duplicates if list is small (though length check handles it)
          return [...top5, ...bottom5]; 
      }
  };

  const displayList = useMemo(() => processList(getActiveList()), [data, activeTab, searchQuery]);

  const formatVal = (val?: number) => {
      if (val === undefined || val === null) return '-';
      return val.toFixed(2);
  };

  const formatPrice = (val?: number) => {
      if (val === undefined || val === null) return '-';
      return val.toLocaleString('en-IN', { maximumFractionDigits: 2 });
  }

  const getChangeColor = (val: number) => {
      if (val > 0) return 'text-green-600';
      if (val < 0) return 'text-red-600';
      return 'text-gray-600';
  };

  return (
    <div className="flex flex-col gap-4">
       <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
           <div className="flex items-center gap-4">
               <div className="flex items-center gap-2">
                   <div className="p-1.5 bg-gray-100 text-gray-500 rounded-lg">
                       <Calendar size={18} />
                   </div>
                   <h3 className="text-lg font-bold text-gray-900">Sectoral/Industrial Pulse</h3>
               </div>

               {/* Duration Dropdown */}
               <div className="relative">
                   <select 
                       value={duration}
                       onChange={(e) => onDurationChange(e.target.value)}
                       className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-xs font-bold rounded-lg pl-3 pr-8 py-1.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer hover:bg-gray-100"
                       disabled={loading}
                   >
                       {DURATION_OPTIONS.map(opt => (
                           <option key={opt.value} value={opt.value}>{opt.label}</option>
                       ))}
                   </select>
                   <ChevronDown size={14} className="absolute right-2 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>
           </div>

           <div className="flex items-center gap-3 w-full sm:w-auto">
               <div className="flex bg-gray-100 p-1 rounded-lg">
                   {(['SECTOR', 'INDUSTRY', 'INDEX'] as const).map(tab => (
                       <button
                           key={tab}
                           onClick={() => { setActiveTab(tab); setSearchQuery(''); }}
                           className={`px-3 py-1.5 text-xs font-medium rounded-md transition-all ${
                               activeTab === tab 
                               ? 'bg-white text-indigo-600 shadow-sm' 
                               : 'text-gray-500 hover:text-gray-700'
                           }`}
                       >
                           {tab === 'INDEX' ? 'Indices' : tab.charAt(0) + tab.slice(1).toLowerCase()}
                       </button>
                   ))}
               </div>

               <div className="relative flex-1 sm:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                       <Search size={14} className="text-gray-400" />
                   </div>
                   <input 
                       type="text"
                       value={searchQuery}
                       onChange={(e) => setSearchQuery(e.target.value)}
                       placeholder={`Search ${activeTab.toLowerCase()}...`}
                       className="w-full bg-white border border-gray-200 text-gray-700 text-sm rounded-lg pl-9 pr-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                   />
               </div>

               <button 
                   onClick={onRefresh}
                   disabled={loading}
                   className="p-1.5 bg-white border border-gray-200 text-gray-500 hover:text-indigo-600 hover:border-indigo-200 rounded-lg transition-all disabled:opacity-50"
                   title="Refresh Data"
               >
                   <RefreshCw size={16} className={loading ? "animate-spin" : ""} />
               </button>
           </div>
       </div>

       <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col max-h-[500px]">
           {loading && !data ? (
               <div className="p-12 flex flex-col items-center justify-center text-gray-400 text-sm italic gap-2">
                   <Loader2 size={24} className="animate-spin text-indigo-500" />
                   Loading sectoral data...
               </div>
           ) : displayList.length > 0 ? (
               <div className="overflow-auto custom-scrollbar">
                   <table className="w-full text-xs text-left whitespace-nowrap">
                       <thead className="bg-gray-50 text-gray-500 font-bold uppercase tracking-wider border-b border-gray-200 sticky top-0 z-10">
                           <tr>
                               {/* Checkbox column only for INDEX tab */}
                               {activeTab === 'INDEX' && <th className="px-4 py-3 w-10"></th>}

                               <th className="px-4 py-3 text-left">Name</th>
                               <th className="px-4 py-3 text-right">Price</th>
                               <th className="px-4 py-3 text-center hidden sm:table-cell">Valuation (PE | PB)</th>
                               <th className="px-4 py-3 text-center hidden md:table-cell">Returns (1W | 1M | 1Y)</th>
                               <th className="px-4 py-3 text-center hidden lg:table-cell w-28">52W Range</th>
                               <th className="px-4 py-3 text-center hidden lg:table-cell">Breadth (Adv/Dec)</th>
                           </tr>
                       </thead>
                       <tbody className="bg-white divide-y divide-gray-50">
                           {displayList.map((item, idx) => {
                               const isPos = item.changePercent >= 0;
                               const total = item.advances + item.declines;
                               const advanceWidth = total > 0 ? (item.advances / total) * 100 : 0;
                               const isTracked = activeTab === 'INDEX' && trackedIndices.includes(item.name);

                               const rangePos = (item.currentVal && item.yearLow && item.yearHigh)
                                   ? ((item.currentVal - item.yearLow) / (item.yearHigh - item.yearLow)) * 100
                                   : 0;

                               // Divider for Top/Bottom split if no search
                               const showDivider = !searchQuery && idx === 5 && displayList.length > 5;
                               const colSpan = activeTab === 'INDEX' ? 7 : 6;

                               return (
                                   <React.Fragment key={`${item.name}-${idx}`}>
                                       {showDivider && (
                                            <tr className="bg-gray-50">
                                                <td colSpan={colSpan} className="px-4 py-1 text-center text-[10px] text-gray-400 font-medium tracking-widest uppercase">
                                                    Bottom Performers
                                                </td>
                                            </tr>
                                       )}
                                       <tr className="hover:bg-gray-50 transition-colors group">
                                           {/* Tracking Checkbox for Index */}
                                           {activeTab === 'INDEX' && (
                                               <td className="px-4 py-3 text-center">
                                                    <button 
                                                        onClick={(e) => { e.stopPropagation(); handleToggleTrack(item.name); }}
                                                        className={`transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 group-hover:text-gray-500'}`}
                                                        title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
                                                    >
                                                        {isTracked ? <CheckSquare size={16} /> : <Square size={16} />}
                                                    </button>
                                               </td>
                                           )}

                                           <td className="px-4 py-3">
                                               <div className="flex items-center gap-2">
                                                   <span className="font-semibold text-gray-800">{item.name}</span>

                                                   {/* External Link */}
                                                   {item.url && (
                                                       <a 
                                                           href={item.url}
                                                           target="_blank"
                                                           rel="noreferrer"
                                                           className="text-gray-300 hover:text-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity"
                                                           onClick={(e) => e.stopPropagation()}
                                                       >
                                                           <ExternalLink size={12} />
                                                       </a>
                                                   )}

                                                   {/* Sector Insights Widget (Bulb Icon) */}
                                                   {item.url && (activeTab === 'SECTOR' || activeTab === 'INDUSTRY') && (
                                                       <SectorInsightsWidget 
                                                           sectorName={item.name}
                                                           sectorUrl={item.url}
                                                           onAddToMover={onAddMover}
                                                           onNavigateStock={onSelectStock}
                                                           addedSymbols={addedSymbols}
                                                       />
                                                   )}
                                               </div>
                                           </td>
                                           <td className="px-4 py-3 text-right">
                                               <div className="flex flex-col items-end">
                                                   <span className="font-medium text-gray-900">{formatPrice(item.currentVal)}</span>
                                                   <span className={`text-[10px] ${getChangeColor(item.changePercent)}`}>
                                                       {isPos ? '+' : ''}{formatVal(item.changePercent)}%
                                                   </span>
                                               </div>
                                           </td>

                                           {/* Valuation */}
                                           <td className="px-4 py-3 text-center text-gray-600 hidden sm:table-cell">
                                               <div className="flex items-center justify-center gap-2">
                                                   <span className="bg-gray-100 px-1.5 py-0.5 rounded text-gray-700" title="PE">{formatVal(item.pe)}</span>
                                                   <span className="text-gray-300">|</span>
                                                   <span className="text-gray-500" title="PB">{formatVal(item.pb)}</span>
                                               </div>
                                           </td>

                                           {/* Returns */}
                                           <td className="px-4 py-3 text-center hidden md:table-cell">
                                               <div className="flex items-center justify-center gap-3">
                                                   <span className={getChangeColor(item.oneWeekChange || 0)}>{formatVal(item.oneWeekChange)}%</span>
                                                   <span className="text-gray-300">|</span>
                                                   <span className={getChangeColor(item.oneMonthChange || 0)}>{formatVal(item.oneMonthChange)}%</span>
                                                   <span className="text-gray-300">|</span>
                                                   <span className={getChangeColor(item.oneYearChange || 0)}>{formatVal(item.oneYearChange)}%</span>
                                               </div>
                                           </td>

                                           {/* 52W Range */}
                                           <td className="px-4 py-3 text-center hidden lg:table-cell">
                                               {item.yearLow && item.yearHigh ? (
                                                   <div className="flex flex-col gap-1 w-full max-w-[100px] mx-auto">
                                                       <div className="flex justify-between text-[9px] text-gray-400">
                                                           <span>{item.yearLow.toLocaleString()}</span>
                                                           <span>{item.yearHigh.toLocaleString()}</span>
                                                       </div>
                                                       <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden relative">
                                                           <div 
                                                               className="absolute h-full w-1.5 bg-indigo-600 rounded-full top-0 ml-[-3px]" 
                                                               style={{ left: `${Math.min(Math.max(rangePos, 0), 100)}%` }}
                                                           ></div>
                                                       </div>
                                                   </div>
                                               ) : (
                                                   <span className="text-gray-300 text-[10px]">-</span>
                                               )}
                                           </td>

                                           {/* Breadth */}
                                           <td className="px-4 py-3 hidden lg:table-cell">
                                               <div className="flex flex-col gap-1 w-full max-w-[100px] mx-auto">
                                                   <div className="flex w-full h-1.5 rounded-full overflow-hidden bg-gray-200">
                                                       <div className="bg-green-500 h-full" style={{ width: `${advanceWidth}%` }}></div>
                                                       <div className="bg-red-500 h-full" style={{ width: `${100 - advanceWidth}%` }}></div>
                                                   </div>
                                                   <div className="flex justify-between text-[9px] text-gray-500">
                                                       <span>{item.advances}</span>
                                                       <span>{item.declines}</span>
                                                   </div>
                                               </div>
                                           </td>
                                       </tr>
                                   </React.Fragment>
                               );
                           })}
                       </tbody>
                   </table>
               </div>
           ) : (
               <div className="p-8 text-center text-gray-400 text-sm italic">
                   No data found for "{searchQuery}".
               </div>
           )}
       </div>
    </div>
  );
};

