                          <Activity size={18} />
                       </div>
                       <h3 className="text-lg font-bold text-gray-900">All Market Indices</h3>
                       <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">
                           {filteredData.length}
